#include <stdio.h>
#include <stdbool.h>
#define MAX 100000
bool isPrime[MAX + 1];
int primeFactors[MAX + 1];
int countKPrimes(int A, int B, int K) {
    int count = 0;
    for (int i = A; i <= B; i++) {
        int factors = 0;
        int num = i;
        for (int j = 2; j * j <= num; j++) {
            if (isPrime[j] && num % j == 0) {
                factors++;
                while (num % j == 0) num /= j;
            }
        }
        if (num > 1) factors++;
        if (factors == K) count++;
    }
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int A, B, K;
        scanf("%d %d %d", &A, &B, &K);
        for (int i = 0; i <= MAX; i++) isPrime[i] = true;
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i <= MAX; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= MAX; j += i) isPrime[j] = false;
            }
        }
        printf("%d\n", countKPrimes(A, B, K));
    }
    return 0;
}

