def count_k_primes(A, B, K):
    is_prime = [True] * (B + 1)
    is_prime[0] = is_prime[1] = False
    for i in range(2, int(B ** 0.5) + 1):
        if is_prime[i]:
            for j in range(i * i, B + 1, i):
                is_prime[j] = False
    count = 0
    for i in range(A, B + 1):
        factors = 0
        num = i
        for j in range(2, int(i ** 0.5) + 1):
            if is_prime[j] and num % j == 0:
                factors += 1
                while num % j == 0:
                    num //= j
        if num > 1:
            factors += 1
        if factors == K:
            count += 1
    return count

